#include <stdio.h>
#include <stdlib.h>

// Structure to represent a pair of X and Y values
typedef struct {
    int x;
    int y;
} Pair;

// Comparison function for sorting pairs based on X values
int compare(const void *a, const void *b) {
    Pair *p1 = (Pair *)a;
    Pair *p2 = (Pair *)b;
    return p1->x - p2->x;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Pair pairs[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &pairs[i].x, &pairs[i].y);
        }
        qsort(pairs, N, sizeof(Pair), compare);
        int maxSum = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (pairs[i].x == pairs[j].x) continue;
                for (int k = 0; k < N; k++) {
                    if (pairs[i].x == pairs[k].x || pairs[j].x == pairs[k].x) continue;
                    maxSum = (maxSum > pairs[i].y + pairs[j].y + pairs[k].y) ? maxSum : pairs[i].y + pairs[j].y + pairs[k].y;
                }
            }
        }
        printf("%d\n", maxSum);
    }
    return 0;
}

