#include <iostream>
#include <algorithm>
using namespace std;

struct Pair {
    int x;
    int y;
};

bool compare(const Pair &a, const Pair &b) {
    return a.x < b.x;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Pair pairs[N];
        for (int i = 0; i < N; i++) {
            cin >> pairs[i].x >> pairs[i].y;
        }
        sort(pairs, pairs + N, compare);
        int maxSum = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (pairs[i].x == pairs[j].x) continue;
                for (int k = 0; k < N; k++) {
                    if (pairs[i].x == pairs[k].x || pairs[j].x == pairs[k].x) continue;
                    maxSum = max(maxSum, pairs[i].y + pairs[j].y + pairs[k].y);
                }
            }
        }
        cout << maxSum << endl;
    }
    return 0;
}

