    let N = parseInt(readline());
    let pairs = [];
    for (let i = 0; i < N; i++) {
        let [x, y] = readline().split(' ').map(Number);
        pairs.push([x, y]);
    }
    pairs.sort((a, b) => a[0] - b[0]);
    let maxSum = 0;
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
            if (pairs[i][0] == pairs[j][0]) continue;
            for (let k = 0; k < N; k++) {
                if (pairs[i][0] == pairs[k][0] || pairs[j][0] == pairs[k][0]) continue;
